import{_ as l}from"./plugin-vue_export-helper-c27b6911.js";import{r,o as i,c as a,a as e,b as o,d as n,e as s}from"./app-01aedd85.js";const d={},c=e("h1",{id:"vllm部署",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#vllm部署","aria-hidden":"true"},"#"),o(" VLLM部署")],-1),g=e("h3",{id:"一、vllm是什么",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#一、vllm是什么","aria-hidden":"true"},"#"),o(" 一、VLLM是什么")],-1),h=e("p",null,"vLLM 是一个用于 LLM 推理和服务的快速易用的库。",-1),p={href:"https://sky.cs.berkeley.edu/",target:"_blank",rel:"noopener noreferrer"},u=e("h3",{id:"二、vllm有什么特点",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#二、vllm有什么特点","aria-hidden":"true"},"#"),o(" 二、VLLM有什么特点")],-1),_={href:"https://blog.vllm.com.cn/2023/06/20/vllm.html",target:"_blank",rel:"noopener noreferrer"},m=e("strong",null,"PagedAttention",-1),f=e("li",null,"对进来的请求进行连续批处理",-1),x=e("li",null,"通过 CUDA/HIP 图实现快速模型执行",-1),b={href:"https://arxiv.org/abs/2210.17323",target:"_blank",rel:"noopener noreferrer"},k={href:"https://arxiv.org/abs/2306.00978",target:"_blank",rel:"noopener noreferrer"},V=s('<h4 id="_2-1、kv-cache" tabindex="-1"><a class="header-anchor" href="#_2-1、kv-cache" aria-hidden="true">#</a> 2.1、KV Cache</h4><p><strong>解码阶段读取模型权重成为瓶颈，前面的词的计算需要用到前面的注意力机制，不能说每次预测下一个词都需要计算一遍前面的词吗？</strong></p><p>采用一种使用空间换时间的思路就是KVcache,其中的k就是自注意力机制中的K矩阵，V是V矩阵，cache就是把前面计算注意力阶段的中间结果。</p><p>KV Cache 就是把这些算好的 K、V 存起来，下次直接用，<strong>不用从头再算</strong>。</p><ul><li>把显存常驻，被解码阶段反复使用指导请求完成</li><li>前缀缓存：把一个请求的前面计算的结果给另一个请求使用，多轮对话和长文本回答。前缀缓存是<strong>全局共享、跨请求复用</strong></li></ul><h5 id="kvcache遇到的问题" tabindex="-1"><a class="header-anchor" href="#kvcache遇到的问题" aria-hidden="true">#</a> KVcache遇到的问题</h5><p>核心就是一个问题，缓存内容太大了，放不下。</p><ul><li>多个请求同时解码显存放不下：KV Cache分页</li><li>前缀缓存是全局共享的，不能无限存。</li></ul><h4 id="_2-2、moe专家架构" tabindex="-1"><a class="header-anchor" href="#_2-2、moe专家架构" aria-hidden="true">#</a> 2.2、MOE专家架构</h4><p>MOE专家架构 是一种<strong>稀疏激活</strong>的模型设计，核心是把一个大网络拆成很多小 “专家”，每次只激活其中几个来干活。</p><p><strong>把原来 1 个大 FFN，换成 N 个小 FFN（专家）+ 1 个门控（路由器）</strong></p><ul><li><strong>专家（Expert）</strong>：小神经网络（通常是标准 FFN），各学各的知识</li><li><strong>门控网络（Gate/Router）</strong>：看输入，给每个 token 选 <strong>Top-K 个专家</strong>（K=1 或 2）</li><li><strong>稀疏激活</strong>：每次只激活少数专家，<strong>大部分参数不干活</strong></li></ul><h5 id="工作流程" tabindex="-1"><a class="header-anchor" href="#工作流程" aria-hidden="true">#</a> 工作流程</h5><p><strong>输入</strong>：一个 token 向量进来</p><p><strong>门控打分</strong>：<code>score = softmax(W_gate · x)</code></p><p><strong>选专家</strong>：取分数最高的 <strong>Top-2</strong> 个</p><p><strong>专家计算</strong>：只让这 2 个专家处理</p><p><strong>加权合并</strong>：<code>输出 = score1·E1(x) + score2·E2(x)</code></p><p><strong>残差 + Norm</strong>：和普通 Transformer 一样</p><h4 id="_2-3、lora量化" tabindex="-1"><a class="header-anchor" href="#_2-3、lora量化" aria-hidden="true">#</a> 2.3、LORA量化</h4><p>LORA是为了解决大模型微调时参数量比较大，是一种低资源微调大模型方法。</p><p><strong>显存占用</strong>以1.5B模型为例</p><ul><li>（推理）参数量fp16——3G</li><li>（推理）KV Cache+激活值——2G</li><li>（训练）梯度——3G</li><li>（训练）AdamW优化器状态——18G</li></ul><p>参数量和训练阶段的AdamW优化器是正相关的关系，所以只需要降低推理阶段的参数量就可以减少显存</p><p>参数2000*1000的矩阵，2000000大概有2千万的数据</p><p>如果使用两个小矩阵一个是<code>2000*8</code>，另外一个是<code>8*1000</code>，那么16000+8000=2.4万的参数这么训练阶段的优化器的参数也会下降。</p><p>使用<strong>低秩的适应矩阵</strong>来表示全量参数</p><h4 id="_2-4、pagedattention" tabindex="-1"><a class="header-anchor" href="#_2-4、pagedattention" aria-hidden="true">#</a> 2.4、PagedAttention</h4><p><strong>PagedAttention（分页注意力）</strong> 是 vLLM 提出的革命性优化，核心是把操作系统的<strong>虚拟内存分页</strong>思想用在 KV Cache 管理上，彻底解决显存碎片、低利用率、前缀难共享的问题。</p><p>把 KV Cache 切成固定大小的块（Block），用块表（Block Table）映射，实现非连续存储、按需分配、前缀共享。</p><h5 id="传统-kv-cache-的死穴-pagedattention-解决什么" tabindex="-1"><a class="header-anchor" href="#传统-kv-cache-的死穴-pagedattention-解决什么" aria-hidden="true">#</a> 传统 KV Cache 的死穴（PagedAttention 解决什么）</h5><ol><li><p><strong>必须连续大块预分配</strong></p><ul><li>每个请求预占最大长度（如 4k）连续显存</li><li>短请求浪费巨量空间，<strong>内部碎片高达 50%–80%</strong></li></ul></li><li><p><strong>显存碎片严重</strong></p><ul><li>大量小空洞无法复用，<strong>外部碎片</strong>导致显存满却装不下新请求</li></ul></li><li><p><strong>前缀完全不能共享</strong></p><ul><li>相同 system prompt / 历史对话，每条请求都存一份 KV</li><li>并发越高浪费越夸张</li></ul></li></ol><h5 id="pagedattention-三大核心机制" tabindex="-1"><a class="header-anchor" href="#pagedattention-三大核心机制" aria-hidden="true">#</a> PagedAttention 三大核心机制</h5><p><strong>1. 分页切块 + 非连续存储</strong></p><ul><li>KV 不再需要连续显存，块散落在显存任意角落</li><li>序列长度增长只需<strong>追加新块</strong>，不用拷贝 / 移动旧数据</li><li>彻底消除<strong>外部碎片</strong>，内部碎片最多浪费 1 块</li></ul><p><strong>2. 按需分配（Dynamic Allocation）</strong></p><ul><li>不是一开始就占满最大长度</li><li>生成时<strong>填满一块再分配下一块</strong></li><li>显存利用率从 30%–50% → <strong>90%+</strong></li></ul><p><strong>3. 写时复制前缀共享（Copy-on-Write, CoW）</strong></p><ul><li>多序列<strong>完全相同的前缀块</strong>，物理上只存一份</li><li>用<strong>引用计数</strong>管理共享</li><li>某序列要修改前缀时，才复制块（写时复制）</li><li>并发场景下<strong>显存节省 30%–70%</strong></li></ul><h4 id="_2-5、continue-batching" tabindex="-1"><a class="header-anchor" href="#_2-5、continue-batching" aria-hidden="true">#</a> 2.5、continue batching</h4><figure><img src="https://hfai-static.high-flyer.cn/static/28d7172c5c27e843bc31bb91aacac16c/a6d36/02.png" alt="02" tabindex="0" loading="lazy"><figcaption>02</figcaption></figure><p>让生成慢的句子别拖累生成快的句子，一个 token 生成完就换下一句，动态拼批次，GPU 永远满负荷干活。</p><p>传统是<strong>静态批处理</strong>：</p><ul><li>一次把一批请求（比如 8 个）打包一起推理</li><li><strong>必须等这批里最慢、最长的句子生成完</strong></li><li>这一批才算结束，才能开始下一批</li></ul><p>结果：</p><ul><li>短句子早早生成完了，<strong>干等着</strong></li><li>GPU 利用率忽高忽低</li><li>并发上不去</li></ul><p>核心思想：<strong>按 token 迭代，而不是按整句</strong></p><ol><li>一批请求一起开始生成</li><li>每生成 <strong>1 个 token</strong> 就检查一遍</li><li>谁生成结束了（遇到结束符），<strong>立刻踢出去</strong></li><li>空出来的位置，<strong>立刻加新请求进来</strong></li><li>剩下没结束的，继续生成下一个 token</li></ol><h3 id="三、vllm的使用指南" tabindex="-1"><a class="header-anchor" href="#三、vllm的使用指南" aria-hidden="true">#</a> 三、VLLM的使用指南</h3><h4 id="_1-核心参数关系-必须懂" tabindex="-1"><a class="header-anchor" href="#_1-核心参数关系-必须懂" aria-hidden="true">#</a> 1. 核心参数关系（必须懂）</h4><ul><li><p><strong><code>--gpu-memory-utilization</code>（默认 0.9）</strong></p><ul><li>不是 “整张卡显存的 90%”，而是 ** 加载权重后剩余显存的 90%** 给 KV Cache</li><li>同卡多实例：必须降到 0.4~0.5，否则必 OOM</li><li>生产建议：<strong>0.85~0.9</strong>，留余量给驱动 / 系统</li></ul></li><li><p><strong><code>--max-model-len</code></strong></p><ul><li>直接决定单请求 KV 大小：<strong>KV 显存 ≈ 2 × 层数 × 头数 × head_dim × max-model-len × dtype 字节</strong></li><li>7B/13B 别盲目开 32k/128k：<strong>长上下文 = 并发暴跌</strong></li><li>业务不需要超长 → 压到 <strong>2048/4096</strong>，并发直接翻倍</li></ul></li><li><p><strong><code>--max-num-seqs</code> / <code>--max-num-batched-tokens</code></strong></p><ul><li><p><code>max-num-seqs</code>：最大并发请求数（默认 256）</p><ul><li>7B：A10(24G) → 64~128；A100(80G) → 256~512</li></ul></li><li><p><code>max-num-batched-tokens</code>：单批最大 token 数（默认 2048）</p><ul><li>离线批量拉满（8192+）提吞吐；在线服务降（2048~4096）控延迟</li></ul></li></ul></li></ul><h4 id="_2-oom-万能急救方案" tabindex="-1"><a class="header-anchor" href="#_2-oom-万能急救方案" aria-hidden="true">#</a> 2. OOM 万能急救方案</h4><ol><li>先降 <strong><code>max-model-len</code></strong>（最有效）</li><li>降 <strong><code>gpu-memory-utilization</code> → 0.8</strong></li><li>降 <strong><code>max-num-seqs</code> / <code>max-num-batched-tokens</code></strong></li><li>加 <strong><code>--swap-space 4</code></strong>（CPU 内存当缓冲）</li><li>启用量化（AWQ/GPTQ）</li><li>多卡张量并行 <code>--tensor-parallel-size N</code>vLLM</li></ol><h4 id="_3-kv-cache-dtype-选择" tabindex="-1"><a class="header-anchor" href="#_3-kv-cache-dtype-选择" aria-hidden="true">#</a> 3. KV Cache dtype 选择</h4><ul><li><strong>A10/H100</strong>：<code>bf16</code>（省显存、速度快）</li><li><strong>3090/4090/A10</strong>：<code>fp16</code>（默认）</li><li><strong>fp8</strong>：仅 Ada/H100 支持（算力 8.0+），盲目开必报错</li></ul>',55);function v(L,K){const t=r("ExternalLinkIcon");return i(),a("div",null,[c,g,h,e("p",null,[o("vLLM 最初是在加州大学伯克利分校的 "),e("a",p,[o("Sky Computing Lab"),n(t)]),o(" 开发的，现已发展成为一个社区驱动的项目，融合了学术界和工业界的贡献。")]),u,e("ul",null,[e("li",null,[o("通过 "),e("a",_,[m,n(t)]),o(" 高效管理注意力键值内存")]),f,x,e("li",null,[o("量化："),e("a",b,[o("GPTQ"),n(t)]),o(", "),e("a",k,[o("AWQ"),n(t)]),o(", INT4, INT8 和 FP8")])]),V])}const y=l(d,[["render",v],["__file","27、Vllm部署.html.vue"]]);export{y as default};
